script.code:
let entry = {{workflowparams:allData}};

if(entry.so_no_type !== -9999 && (
  !entry.so_no || entry.so_no === null || entry.so_no === ''
)) {
  entry.so_no = 'draft'
}

return { entry };

return {
  required_fields: JSON.stringify([
  { name: "plant_name", label: "Plant" },
  { name: "so_no", label: "Sales Order Number" },
  { name: "acc_integration_type", label: "Accounting Integration Type" },
  {
    name: "table_so",
    label: "Item Information",
    isArray: true,
    arrayType: "object",
    arrayFields: [],
  },
]),
  data: JSON.stringify({
    plant_name: {{node:code_node_hVnUCBf3.data.entry.plant_name}},
    so_no: {{node:code_node_hVnUCBf3.data.entry.so_no}},
    table_so: {{node:code_node_hVnUCBf3.data.entry.table_so}},
    acc_integration_type: {{node:code_node_hVnUCBf3.data.entry.acc_integration_type}}
  })
}

let entry = {{workflowparams:allData}};

if (
  entry.so_no_type !== -9999 &&
  (!entry.so_no ||
    entry.so_no === null ||
    entry.so_no === "" ||
    entry.previous_status == "Draft")
) {
  entry.so_no = 'issued'
}

if(!entry.need_cl || entry.need_cl === '' || entry.need_cl === null) {
  if(entry.acc_integration_type !== 'No Accounting') {
    entry.need_cl = 'required'
  } else {
    entry.need_cl = 'not required'
  }
}

return { entry };

return {
  required_fields: JSON.stringify([
  { name: "so_no", label: "SO Number" },
  { name: "customer_name", label: "Customer" },
  { name: "plant_name", label: "Plant" },
  { name: "so_date", label: "Sales Order Date" },
  { name: "so_payment_term", label: "Payment Term" },
  { name: "acc_integration_type", label: "Accounting Integration Type" },
  {
    name: "table_so",
    label: "Item Information",
    isArray: true,
    arrayType: "object",
    arrayFields: [],
  },
]),
  data: JSON.stringify({
    plant_name: {{node:code_node_X4j8BSXd.data.entry.plant_name}},
    so_date: {{node:code_node_X4j8BSXd.data.entry.so_date}},
    so_payment_term: {{node:code_node_X4j8BSXd.data.entry.so_payment_term}},
    so_no: {{node:code_node_X4j8BSXd.data.entry.so_no}},
    customer_name: {{node:code_node_X4j8BSXd.data.entry.customer_name}},
    table_so: {{node:code_node_X4j8BSXd.data.entry.table_so}},
    acc_integration_type: {{node:code_node_X4j8BSXd.data.entry.acc_integration_type}}
  })
}

let table = {{node:code_node_X4j8BSXd.data.entry}};

table.table_so = table.table_so.filter(item => (item.item_name || item.so_desc || item.item_id) && item.so_quantity > 0)

return { table };

return {
  message: 'This SO has 0 total amount. Do you wish to continue to create SI?'
}

const draftGDCount = {{node:search_node_TmnClGAM.data.total}};
const draftSICount = {{node:search_node_UmwyM0pM.data.total}};
let message = [];
let status = 'Passed';

if(draftGDCount > 0) {
  const draftGDNo = {{node:search_node_TmnClGAM.data.data.delivery_no}};
  message.push(draftGDNo);
}

if(draftSICount > 0) {
  const draftSINo = {{node:search_node_UmwyM0pM.data.data.sales_invoice_no}};
  message.push(draftSINo);
}

if(message.length > 0) {
  status = 'Failed'
}

return {
  status: status,
  message: status === 'Passed' ? '' : 'The sales order has existing GD/SI records in draft status. Proceeding will delete these record: ' + message.join(', ')
}

const message = {{node:workflow_node_1IYhCFaV.data.message}};
const isBlock = message.indexOf('Block - ') !== -1 ? 'block' : 'override';

return {
  isBlock
}

let updatedLineItem = [];
let entry = {{workflowparams:allData.so_status}} == 'Draft' ? {{node:code_node_hVnUCBf3.data.entry}} : {{node:code_node_rPqQy5CD.data.table}};

for(const [index, soLineItem] of entry.table_so.entries()) {
  // Create a new object with formatted values
  const formattedItem = {
    ...soLineItem,
    // Number formatting
    unrestricted_qty: parseFloat(soLineItem.unrestricted_qty || 0).toFixed(3),
    base_unrestricted_qty: parseFloat(soLineItem.base_unrestricted_qty || 0).toFixed(3),
    so_quantity: parseFloat(soLineItem.so_quantity || 0).toFixed(3),
    so_item_price: parseFloat(soLineItem.so_item_price || 0).toFixed(4),
    so_gross: parseFloat(soLineItem.so_gross|| 0).toFixed(4),
    so_discount: parseFloat(soLineItem.so_discount || 0).toFixed(4),
    so_discount_amount: parseFloat(soLineItem.so_discount_amount || 0).toFixed(4),
    so_tax_amount: parseFloat(soLineItem.so_tax_amount || 0).toFixed(4),
    min_price: parseFloat(soLineItem.min_price || 0).toFixed(4),
    max_price: parseFloat(soLineItem.max_price || 0).toFixed(4),
    so_amount: parseFloat(soLineItem.so_amount || 0).toFixed(4),
    production_planned_qty: parseFloat(soLineItem.so_quantity || 0).toFixed(3),
    production_status: "Not Created",
    outstanding_quantity: (parseFloat(soLineItem.so_quantity || 0) - parseFloat(soLineItem.delivered_qty || 0)).toFixed(3),
    // Other field assignments
    plant_id: entry.plant_name || "",
    customer_id: entry.customer_name || "",
    payment_term_id: entry.so_payment_term || "",
    sales_person_id: entry.so_sales_person || "",
    billing_state_id: entry.billing_address_state || "",
    billing_country_id: entry.billing_address_country || "",
    shipping_state_id: entry.shipping_address_state || "",
    shipping_country_id: entry.shipping_address_country || "",
    area_id: entry.so_area_id || "",
    line_index: index + 1,
    organization_id: entry.organization_id,
    line_status: !soLineItem.line_status || soLineItem.line_status === '' || soLineItem.line_status === 'Draft' ? entry.so_status === 'Processing' ? 'Issued' : entry.so_status : soLineItem.line_status,
    access_group: entry.access_group || [],
    agent_user_id: entry.so_agent_user_id || ''
  };

  updatedLineItem.push(formattedItem);
}

entry.need_cl = ''

entry.production_status = !entry.production_status || entry.production_status === '' ? 'Not Created' : entry.production_status;

entry.si_status = !entry.si_status || entry.si_status === '' ? 'Not Created' : entry.si_status;
entry.so_total_gross = parseFloat(entry.so_total_gross || 0).toFixed(4);
entry.so_total_discount = parseFloat(entry.so_total_discount || 0).toFixed(4);
entry.so_total_tax = parseFloat(entry.so_total_tax || 0).toFixed(4);
entry.so_total = parseFloat(entry.so_total || 0).toFixed(4);
entry.myr_total_amount = parseFloat(entry.myr_total_amount || 0).toFixed(4);


entry.table_so = updatedLineItem;

return { entry };

const lineItem = {{node:code_node_BtxYhPym.data.entry.table_so}};

const uniqueItemIDs = [
  ...new Set(lineItem.filter((item) => item.item_name).map((item) => item.item_name))
];

return {
  itemIDs: uniqueItemIDs
}

const accIntegrationData = {{node:get_node_6NZZfFj5.data.data}};
const soData = {{node:code_node_9wKKlXUI.data.soData}};

if(accIntegrationData.auto_post_so === 1 && soData.posted_status !== 'Posted') {
  return {
    result: 'Auto Post'
  }
}

return {
  result: ''
}

const soData = {{node:code_node_9wKKlXUI.data.soData}};
const siData = soData.auto_si === 1 ? {{node:workflow_node_FQlYniVW.data}} : null;

return {
  data: {
    so_id: soData.id,
    so_no: soData.so_no,
    si_id: siData?.id ?? null,
    si_no: siData?.si_no ?? null
  }
}
